function Particles() {
  const items = ["🍣", "🌸", "🍙", "🥢", "🌸", "🍣", "🎋", "🍣", "🌸", "🥟", "🍣", "🌸"];
  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", overflow: "hidden", zIndex: 0 }}>
      {items.map((item, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            fontSize: `${14 + Math.random() * 18}px`,
            left: `${Math.random() * 100}%`,
            top: `-30px`,
            opacity: 0.15 + Math.random() * 0.2,
            animation: `floatDown ${8 + Math.random() * 12}s linear infinite`,
            animationDelay: `${Math.random() * 10}s`,
          }}
        >
          {item}
        </div>
      ))}
    </div>
  );
}

function Card({ children, screenKey }) {
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    setVisible(false);
    const t = setTimeout(() => setVisible(true), 50);
    return () => clearTimeout(t);
  }, [screenKey]);

  return (
    <div style={{
      opacity: visible ? 1 : 0,
      transform: visible ? "translateY(0) scale(1)" : "translateY(40px) scale(0.92)",
      transition: "all 0.6s cubic-bezier(0.34, 1.56, 0.64, 1)",
      background: "rgba(255,255,255,0.07)",
      backdropFilter: "blur(20px)",
      WebkitBackdropFilter: "blur(20px)",
      borderRadius: "28px",
      padding: "36px 28px",
      maxWidth: "420px",
      width: "90vw",
      boxShadow: "0 20px 60px rgba(0,0,0,0.4), 0 0 0 1px rgba(255,255,255,0.08), inset 0 1px 0 rgba(255,255,255,0.1)",
      position: "relative",
      zIndex: 2,
    }}>
      {children}
    </div>
  );
}

function ActionButton({ children, onClick, variant = "primary", delay = 0 }) {
  const [show, setShow] = useState(false);
  const [hover, setHover] = useState(false);
  const [pressed, setPressed] = useState(false);

  useEffect(() => {
    setShow(false);
    const t = setTimeout(() => setShow(true), 300 + delay);
    return () => clearTimeout(t);
  }, [delay]);

  const isPrimary = variant === "primary";

  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => { setHover(false); setPressed(false); }}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      onTouchStart={() => setPressed(true)}
      onTouchEnd={() => setPressed(false)}
      style={{
        opacity: show ? 1 : 0,
        transform: show
          ? pressed ? "translateY(2px) scale(0.97)"
          : hover ? "translateY(-3px) scale(1.03)"
          : "translateY(0) scale(1)"
          : "translateY(20px) scale(0.8)",
        transition: "all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1)",
        background: isPrimary
          ? "linear-gradient(135deg, #FF6B6B 0%, #ee5a24 50%, #f0932b 100%)"
          : "linear-gradient(135deg, rgba(255,255,255,0.12) 0%, rgba(255,255,255,0.06) 100%)",
        color: "#fff",
        border: isPrimary ? "none" : "1px solid rgba(255,255,255,0.15)",
        borderRadius: "18px",
        padding: "16px 28px",
        fontSize: "17px",
        fontFamily: "'Nunito', sans-serif",
        fontWeight: 700,
        cursor: "pointer",
        width: "100%",
        letterSpacing: "0.3px",
        boxShadow: isPrimary
          ? hover ? "0 12px 35px rgba(238,90,36,0.5)" : "0 8px 25px rgba(238,90,36,0.35)"
          : hover ? "0 8px 25px rgba(0,0,0,0.3)" : "0 4px 15px rgba(0,0,0,0.2)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        gap: "10px",
      }}
    >
      {children}
    </button>
  );
}

function Portrait({ mood }) {
  const faces = {
    together: { emoji: "🐱🐭", bg: "linear-gradient(135deg, #6c5ce7, #a29bfe)" },
    love: { emoji: "😻", bg: "linear-gradient(135deg, #fd79a8, #e84393)" },
    thinking: { emoji: "🤔", bg: "linear-gradient(135deg, #fdcb6e, #f39c12)" },
    cool: { emoji: "😏", bg: "linear-gradient(135deg, #e17055, #d63031)" },
  };
  const face = faces[mood] || faces.together;
  const [bounce, setBounce] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      setBounce(true);
      setTimeout(() => setBounce(false), 600);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{
      width: "100px", height: "100px", borderRadius: "50%",
      background: face.bg,
      display: "flex", alignItems: "center", justifyContent: "center",
      fontSize: mood === "together" ? "36px" : "48px",
      boxShadow: "0 10px 30px rgba(0,0,0,0.3), inset 0 -2px 6px rgba(0,0,0,0.1)",
      margin: "0 auto 20px",
      transform: bounce ? "scale(1.12) rotate(5deg)" : "scale(1) rotate(0deg)",
      transition: "transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1)",
      border: "3px solid rgba(255,255,255,0.2)",
    }}>
      {face.emoji}
    </div>
  );
}

function SushiBanner() {
  return (
    <div style={{ fontSize: "32px", textAlign: "center", margin: "0 0 8px", letterSpacing: "6px", filter: "drop-shadow(0 2px 4px rgba(0,0,0,0.3))" }}>
      🍣🥢🍙
    </div>
  );
}

